export function formatFullName(firstName: string, lastName: string | null | undefined): string {
	return firstName + (lastName ? ` ${lastName}` : '');
}

export function dbUserToUser(row: DbUser): User {
	return {
		id: row.id,
		name: formatFullName(row.firstName, row.lastName),
		firstName: row.firstName,
		lastName: row.lastName,
		email: row.email ?? '',
		role: row.role as User['role'],
		active: row.active
	};
}

const noteSelection = {
	id: crmNotes.id,
	content: crmNotes.content,
	authorId: crmNotes.authorId,
	authorName: sql<string>`${crmUsers.firstName} || case when ${crmUsers.lastName} is null or ${crmUsers.lastName} = '' then '' else ' ' || ${crmUsers.lastName} end`,
	leadId: crmNotes.leadId,
	organizerId: crmNotes.organizerId,
	createdAt: crmNotes.createdAt
};

if (term) {
	conds.push(ilike(crmUsers.firstName, `%${term.replace(/[\\%_]/g, '\\$&')}%`));
}

